    base:desc "Grafana dashboard enabler for time‑series visualization."
    DTDFVocab:enables TimeSeriesVisualizationService
]

instance TrajectoryGenEnabler : DTDFVocab:Enabler [
    base:desc "Enabler for the trajectory generator service using the kinematic model."
    DTDFVocab:enables OptimalTrajectoryGenerationService
]

instance SimulationEnabler : DTDFVocab:Enabler [
    base:desc "Enabler for the real‑time simulation service of the crane."
    DTDFVocab:enables RealTimeSimulationService
]

instance ContinuousValidationEnabler : DTDFVocab:Enabler [
    base:desc "Enabler for the continuous validation service comparing measured and simulated trajectories."
    DTDFVocab:enables ContinuousValidationService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
