    base:desc "Service that visualizes time‑series data in Grafana via the DashboardEnabler."
    DTDFVocab:provides SimulationVisualizationInsight
]

instance OptimalTrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Service that generates optimal trajectories using the KinematicModel via the TrajectoryGenEnabler."
    DTDFVocab:provides OptimalPathCalculationAction
]

instance RealTimeSimulationService : DTDFVocab:Service [
    base:desc "Service that runs real‑time simulation of the crane and its controllers via the SimulationEnabler."
    DTDFVocab:provides SimulationVisualizationInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Service that continuously validates measured versus simulated trajectories via the ContinuousValidationEnabler."
    DTDFVocab:provides TrajectoryDeviationAlertInsight
]

instance HistoricalDataAnalysisService : DTDFVocab:Service [
    base:desc "Service that performs historical data analysis of crane logs via the DatabaseEnabler."
    DTDFVocab:provides HistoricalLogAnalysisAction
]

// Insights & Actions -------------------------------------------------------
