instance LabScaleGantryCraneEnv : DTDFVocab:Environment [
    base:contains CartMotorDriverActuator, HoistMotorDriverActuator, ElectromagnetActuator,
              SwingAngleEncoder, Anemometer, CartMotorPositionEncoder, HoistMotorPositionEncoder
