instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Control commands generated by the Trajectory Generator Service and Control Application are transmitted via MQTT to the Physical Crane Interface to drive the cart and hoist motors and the electromagnet; Validation alerts are also forwarded to the Human‑Machine Interface for operator action."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time continuous operation with sensor data logged at millisecond granularity, trajectory generation and validation executed per motion cycle, and near real‑time dashboard updates."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Services are orchestrated via Docker networking: sensor data and control messages travel over MQTT topics; simulation, trajectory generation and validation services subscribe to relevant topics; results are persisted in TimescaleDB and visualised by Grafana, while operator control is provided through a Python HMI."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design: CAD models in Autodesk Fusion360 and Capella Arcadia models capture the crane geometry and kinematics. Development: Python implementation of the kinematic model, simulation, and digit twin services. Operation: Continuous logging, real‑time control, simulation, and validation during crane use."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous Validation Service computes a distance metric between measured and simulated trajectories, compares against a predefined threshold, and triggers alerts; the simulation uses a validated kinematic model to ensure swing‑motion residuals are minimized."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Physical–to–virtual: Python Physical Crane Interface streams sensor data over TCP to the Logging Application, which writes to TimescaleDB via PostgreSQL’s native protocol. Virtual–to–physical: Control commands are published on MQTT topics (broker Mosquitto) and consumed by the Control Application, which then commands the Physical Crane Interface. All services are networked within Docker Compose, using default ports (PostgreSQL 5432, MQTT 1883)."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "Containerised deployment via Docker and docker‑compose on a local workstation, with services exposed on local ports; repository hosted on GitHub for version control and reproducibility."
]
